function fieldVal(lead, fieldId) {
  const arr = Array.isArray(lead.custom_fields_values) ? lead.custom_fields_values : [];
  const hit = arr.find((x) => Number(x.field_id) === Number(fieldId));
  if (!hit || !Array.isArray(hit.values) || hit.values.length === 0) return "";
  const v = hit.values[0].value;
  return v === null || v === undefined ? "" : String(v);
}

function parseDateAny(v) {
  const s = String(v || "").trim();
  if (!s) return null;
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  if (/^\d{2}\/\d{2}\/\d{4}$/.test(s)) {
    const [mm, dd, yyyy] = s.split("/");
    return `${yyyy}-${mm}-${dd}`;
  }
  if (/^\d+$/.test(s)) {
    const n = Number(s);
    if (Number.isFinite(n)) {
      const ms = n < 100000000000 ? n * 1000 : n;
      const dNum = new Date(ms);
      if (!Number.isNaN(dNum.getTime())) return dNum.toISOString().slice(0, 10);
    }
  }
  const d = new Date(s);
  if (!Number.isNaN(d.getTime())) return d.toISOString().slice(0, 10);
  return null;
}

function todayIso(tz) {
  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone: tz,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  }).formatToParts(new Date());
  const y = parts.find((p) => p.type === "year")?.value;
  const m = parts.find((p) => p.type === "month")?.value;
  const d = parts.find((p) => p.type === "day")?.value;
  return `${y}-${m}-${d}`;
}

function kommoNowIso() {
  const d = new Date();
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, "0");
  const day = String(d.getUTCDate()).padStart(2, "0");
  const h = String(d.getUTCHours()).padStart(2, "0");
  const min = String(d.getUTCMinutes()).padStart(2, "0");
  const s = String(d.getUTCSeconds()).padStart(2, "0");
  return `${y}-${m}-${day}T${h}:${min}:${s}+00:00`;
}

function daysBetween(aIso, bIso) {
  const a = new Date(aIso + "T00:00:00Z");
  const b = new Date(bIso + "T00:00:00Z");
  return Math.round((b.getTime() - a.getTime()) / 86400000);
}

function money(n) {
  const x = Number(n || 0);
  return "$" + x.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

async function req(method, path, body) {
  return await this.helpers.httpRequest({
    method,
    url: CFG.baseUrl + path,
    headers: {
      Authorization: "Bearer " + CFG.token,
      "Content-Type": "application/json",
    },
    body,
    json: true,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });
}

async function note(leadId, text) {
  await req("POST", "/api/v4/leads/" + leadId + "/notes", [{ note_type: "common", params: { text } }]);
}

async function task(leadId, responsibleId, text) {
  const complete = Math.floor(Date.now() / 1000) + 86400;
  await req("POST", "/api/v4/tasks", [{
    text,
    complete_till: complete,
    entity_id: Number(leadId),
    entity_type: "leads",
    responsible_user_id: Number(responsibleId || 14811623),
  }]);
}

const logs = [];
const today = todayIso(CFG.timezone);

const listRes = await req("GET", "/api/v4/leads?limit=250&with=custom_fields_values,tags");
if (listRes.statusCode >= 400) {
  throw new Error("Lead list failed: " + listRes.statusCode + " " + JSON.stringify(listRes.body || {}));
}

const leads = ((((listRes.body || {})._embedded || {}).leads) || []);
for (const lead of leads) {
  const tags = ((((lead._embedded || {}).tags) || [])).map((t) => String(t.name || "").toLowerCase().trim());
  if (!tags.includes(String(CFG.tag).toLowerCase())) continue;
  if (Number(lead.pipeline_id) !== Number(CFG.pipelineId)) continue;
  if (Number(lead.status_id) === Number(CFG.paidStatusId)) continue;

  const documento = fieldVal(lead, CFG.fieldIds.documento);
  const saldo = Number(fieldVal(lead, CFG.fieldIds.saldo_pendiente) || 0);
  if (!(saldo > 0)) continue;

  const dueIso = parseDateAny(fieldVal(lead, CFG.fieldIds.fecha_venc_date) || fieldVal(lead, CFG.fieldIds.fecha_venc_text));
  if (!dueIso) continue;
  const d = daysBetween(today, dueIso);
  if (![3, 2, 1].includes(d)) continue;

  const f3 = fieldVal(lead, CFG.fieldIds.aviso_3d);
  const f2 = fieldVal(lead, CFG.fieldIds.aviso_2d);
  const f1 = fieldVal(lead, CFG.fieldIds.aviso_1d);
  if ((d === 3 && f3) || (d === 2 && f2) || (d === 1 && f1)) continue;

  let msg = "";
  if (d === 3) {
    msg = "Recordatorio: tu factura " + documento + " vence en 3 dias. Por favor realiza tu pago antes de la fecha limite.";
  } else if (d === 2) {
    msg = "Recordatorio: tu factura " + documento + " vence en 2 dias. Tu saldo pendiente es " + money(saldo) + ".";
  } else {
    msg = "Aviso final: tu factura " + documento + " vence en 1 dia. Tu saldo pendiente es " + money(saldo) + ".";
  }

  const sendRes = await req("PATCH", "/api/v4/chats/templates", [{
    id: CFG.templateId,
    content: msg,
    entity_id: Number(lead.id),
    entity_type: 2,
  }]);

  let sentOk = sendRes.statusCode < 400;
  if (!sentOk) {
    const botRes = await req("POST", "/api/v2/salesbot/run", [{
      bot_id: CFG.salesbotId,
      entity_id: Number(lead.id),
      entity_type: 2,
    }]);
    if (botRes.statusCode < 400) {
      const retrySend = await req("PATCH", "/api/v4/chats/templates", [{
        id: CFG.templateId,
        content: msg,
        entity_id: Number(lead.id),
        entity_type: 2,
      }]);
      sentOk = retrySend.statusCode < 400;
    }
  }

  if (sentOk) {
    const nowIso = kommoNowIso();
    const markField =
      d === 3 ? CFG.fieldIds.aviso_3d :
      d === 2 ? CFG.fieldIds.aviso_2d :
      CFG.fieldIds.aviso_1d;
    await req("PATCH", "/api/v4/leads", [{
      id: Number(lead.id),
      custom_fields_values: [{ field_id: markField, values: [{ value: nowIso }] }],
    }]);
  } else {
    await note(lead.id, "No se pudo enviar recordatorio automatico " + d + "D. Revisar canal de chat.");
    await task(lead.id, lead.responsible_user_id, "Cobranza manual: no se pudo enviar recordatorio " + d + "D");
  }

  logs.push({
    lead_id: Number(lead.id),
    documento: documento,
    days_to_due: d,
    reminder_type: d + "D",
    send_result: sentOk ? "sent" : "failed",
    abono_detectado: null,
    saldo_nuevo: saldo,
  });
}

return [{ json: { run_at: new Date().toISOString(), count: logs.length, logs } }];

